import React from "react";
import { Formik, Field, Form, ErrorMessage, FieldArray } from 'formik';
import * as Yup from 'yup';
import * as k from 'yup-phone';
import { useForm, ValidationError } from '@formspree/react';

const Contact = (props) =>{
  		const [state, handleSubmit] = useForm("xgedalpk");
		const style = { height:'40px',};
		const err = {color:'red'};

		return (
				<div style={ {backgroundColor:'#1f1f1f'} } >
					<div className="container">
						<div className="d-flex justify-content-center align-items-center"> <h1 class="section-title"><span class="text-white">Contact Me</span></h1> </div>				
						<div className="d-flex justify-content-center align-items-center"> 
							<div className="w-75">
								<Formik
										       initialValues={{ name: '' , email: '', phone: '', message: '',}}
										       validationSchema={Yup.object({
										         name: Yup.string().required('Required'),
										         
										         email: Yup.string().required('Required').email('Invalid email address'),

										         phone: Yup.string().required('Required').max(20, 'Must be 20 characters or less'),

										         message: Yup.string().required('Required'),
										       })}
										       onSubmit={
												       (values, { setSubmitting, resetForm}) => {

												       setSubmitting(true);
												       handleSubmit(values);
												       resetForm();
												       alert('Thank You. I will be in contact as soon as possible.');

												       }
											   }

								>
									<Form >

										<label for="name"><h1 class="section-title"><span class="text-white">Name or Company</span></h1></label>
										<Field style={style} name={'name'} className={"form-control"} />
										<ErrorMessage name="name">
										{msg => <div style={ err }>{msg}</div>}
										</ErrorMessage> 

										<label for="email"><h1 class="section-title"><span class="text-white">Email</span></h1></label>
										<Field style={style} name={'email'} className={"form-control"} />
										<ErrorMessage name="email">
										{msg => <div style={ err }>{msg}</div>}
										</ErrorMessage> 

										<label for="phone"><h1 class="section-title"><span class="text-white">Phone</span></h1></label>
										<Field style={style} name={'phone'} className={"form-control"} />
										<ErrorMessage name="phone">
										{msg => <div style={ err }>{msg}</div>}
										</ErrorMessage> 

										<label for="message"><h1 class="section-title"><span class="text-white">Message</span></h1></label>
										<Field style={ {height:'70px'} } as={'textarea'} name={'message'} className={"form-control"} />
										<ErrorMessage name="message">
										{msg => <div style={ err }>{msg}</div>}
										</ErrorMessage>
										<br/>  


										<button className="btn btn-danger mt-2" type="submit"> <h1 class="section-title"><span class="text-white">Submit</span></h1> </button> 

									</Form>


								</Formik>
						<div className="d-flex justify-content-center align-items-center"> <h1 class="section-title"><span class="text-white">My Email: <a class="text-white" href="mailto: beodwilson@gmail.com">beodwilson@gmail.com</a></span></h1> </div>				
							</div>
						</div>
					</div>
				</div>
		);
}





export default Contact;